import { Compute, OpenTable, Select, SelectRule } from './timeline-components/index.js'

export default class {
  constructor (uid, table) {
    this._currentId = 1

    this.uid = uid
    this.ops = []
    this.columns = []

    this.add('OpenTable', { table })
  }

  getNextId () {
    return this._currentId++
  }

  add (opType, options) {
    var op
    if (opType === 'OpenTable') {
      op = new OpenTable(options)
    } else if (opType === 'Select') {
      op = new Select()
    } else if (opType === 'Compute') {
      op = new Compute()
    }

    op.id = this.getNextId()

    // Set the new rule after the id of op has been set
    if (opType === 'Select') {
      this.addRule(op)
    }

    this.ops.push(op)
  }

  remove (op) {
    this.ops = this.ops.filter(o => {
      return o.id !== op.id
    })
  }

  addRule (op) {
    var rule = new SelectRule()
    rule.id = this.getNextId()

    if (op) {
      op.data.rules.push(rule)
    }

    return rule
  }

  removeRule (op, rule) {
    op.data.rules = op.data.rules.filter(r => {
      return r.id !== rule.id
    })
  }
}



